40	 *
41	 * 語意：目前在 MainGame 局（round===0）且整包有多個 RoundInfo（觸發 FG）且尚未進 FG。
42	 * FG 進行中（isFreeGame=true）或非首局（round≠0）或單局（len≤1）皆為 false。
43	 *
44	 * @param round         當前局索引（CurPlateIndex）
45	 * @param roundQueueLen SpinAck.RoundQueue.length（缺值傳 0）
46	 * @param isFreeGame    GameView.IsFreeGame
47	 */
48	export function IsGoingToFreePure(
49	    round: number,
50	    roundQueueLen: number,
51	    isFreeGame: boolean
52	): boolean
53	{
54	    return round === 0 && roundQueueLen > 1 && !isFreeGame;
55	}
