import { _decorator, error, log } from "cc";
import GameView from "../GameView";
import { BaseState, commonGameManager, eventManager, msgBoxManager, newBottombarManager, newExtraManager, stateManager } from "db://astarte-framework/Managers";
import { CommonState, Define } from "db://astarte-framework/utilis";
import { FeverGameType } from "../Game_Define";
import { FREE_GAME_ROUND_UI_EVENT } from "../FreeGame/FreeGameRoundUI";
import protocol from "@igs-arcade-division-rd2/uk_872_eyestrike2_proto/ar2es2Proto.js";
import { MULTIPLIER_EVENT } from "../Multiplier/MultiplierManager";
import { MAGIC_POT_EVENT } from "../MagicPot/MagicPotController";
import { FakeReelBetMode } from "../FakeReelManager";
const { ccclass } = _decorator;

@ccclass( "UnshowPrepareState" )
export class UnshowPrepareState extends BaseState
{
    private m_gameView: GameView = null;

    /** @ch 起始盤面索引 */
    private m_startRound: number = 0;

    /** @ch 起始盤面資訊 */
    private m_startRoundInfo: protocol.ar2es2Proto.IRoundInfo = null;

    /** @ch 上一輪累積贏分 */
    private m_previousAccumulatedWinValue: number = 0;

    /** @ch 未顯示轉軸確認隊列 */
    private m_unshowSpinAckQue: protocol.ar2es2Proto.IRoundInfo[] = [];

    constructor( gameView: GameView )
    {
        super();
        this.m_gameView = gameView;
    }

    public async OnEnter()
    {
        if (!commonGameManager.HasUnshow) {
            log("[UnshowPrepareState] No unshow data, skip this state");
            return;
        }

        log("OnEnter State: UnshowPrepare");
        newExtraManager.HasUnshow = false;

        newBottombarManager.SetBarNodeVisiable(true);
        if (this.m_gameView.GameIntro) {
            this.m_gameView.GameIntro.node.active = false;
        }

        this.m_unshowSpinAckQue = this.m_gameView.UnshowSpinAck?.RoundQueue ?? [];
        this.m_startRound = Math.trunc(commonGameManager.UnshowStartRound ?? 0);
        if (this.m_unshowSpinAckQue.length > 0) {
            const lastIndex = this.m_unshowSpinAckQue.length - 1;
            if (this.m_startRound < 0 || this.m_startRound > lastIndex) {
                error(`[UnshowPrepareState] startRound (${this.m_startRound}) out of range [0, ${lastIndex}]`);
                this.m_startRound = Math.min(Math.max(0, this.m_startRound), lastIndex);
            }
            this.m_gameView.SetUnshowPlateCursor( this.m_startRound );
            this.m_startRoundInfo = this.m_unshowSpinAckQue[this.m_startRound];
        }
        else {
            error("[UnshowPrepareState] RoundQueue is empty");
            this.m_startRound = 0;
            this.m_gameView.SetUnshowPlateCursor( 0 );
            this.m_startRoundInfo = null;
        }

        this.m_previousAccumulatedWinValue = 0;

        // 檢查是否為FreeGame 或 RespinGame
        if (
            this.m_unshowSpinAckQue.length > 1
            && this.m_startRound >= 1
            && this.m_startRound < this.m_unshowSpinAckQue.length
        ) {
            let plateSymbol = this.m_startRoundInfo?.PlateQueue?.[0]?.PlateSymbol ?? [];
            if (this.m_startRoundInfo.CurrFeverGameType === FeverGameType.FreeGame) {
                // 地Bar設定
                newBottombarManager.SetEnterFree();

                // FG 旗標設定
                this.m_gameView.IsFreeGame = true;
                this.m_gameView.IsFirstRound = false;

                plateSymbol = this.m_startRoundInfo?.PlateQueue?.[0]?.PlateSymbol ?? [];
            }
            // 原 else（CurrFeverGameType===RespinGame）為不可達死碼已刪：
            //   startRound≥1 ⟹ 必在 FreeGame（MG 僅 round 0），CurrFeverGameType 不會是 respin。
            //   Respin 中段斷線時 server UnshowStartRound 指回該 RoundInfo，從 plate 0（sub=0）重播整局，
            //   IsRespinGame 由流程重入 ENTER_RESPIN 自然重建（BC-8 待 Respin 上線實測）。

            // 計算上一輪累積贏分
            for (let i = 0; i < this.m_startRound; i++) {
                this.m_previousAccumulatedWinValue += this.m_unshowSpinAckQue[i].RoundWin;
            }

            // 設定起始盤面即上一手盤面
            this.m_gameView.SlotReels.SetPlateSymbolForUnshow(plateSymbol);

            // 原 if(IsRespinGame) HandleRespinGame()：unshow 不再以 Respin 身分恢復，改從 plate 0（sub=0）
            // 重播整局、由流程重入 ENTER_RESPIN 自然重建鎖定（BC-8 待 Respin 上線實測）。
        }

        // 恢復背景音樂
        this.RestoreBgm();

        // 恢復UI
        await this.RestoreUI();

        msgBoxManager.ShowMessageBox(
            Define.StringKey.MSGBOX_UNSHOW_BACK,
            Define.StringKey.MSGBOX_TITLE_SYSTEM_INFO,
            () => {
                stateManager.NextState(CommonState.SPIN);
            }
        );
    }

    public OnProcess()
    {
    }

    public OnLeave()
    {
        this.m_startRoundInfo = null;
        this.m_previousAccumulatedWinValue = 0;
    }

    /**
     * @ch 恢復FreeGame UI
     */
    private RestoreFreeGameUI()
    {
        log( "RestoreFreeGameUI" );

        // 初始化免費遊戲回合數字
        const nowRound = this.m_startRoundInfo?.FreeNowRound ?? 0;
        const totalRound = this.GetFreeGameTotalRound();
        eventManager.Dispatch( FREE_GAME_ROUND_UI_EVENT.INIT, nowRound, totalRound );
        eventManager.Dispatch( FREE_GAME_ROUND_UI_EVENT.SHOW );

        // 恢復贏分
        this.RestoreWinValue();
    }

    /**
     * @ch 恢復RespinGame UI
     */
    private RestoreRespinGameUI()
    {
        log( "RestoreRespinGameUI" );

        // 恢復贏分
        this.RestoreWinValue();
    }

    /**
     * @ch 恢復MainGame UI
     */
    private RestoreMainGameUI()
    {
        log( "RestoreMainGameUI" );

        // 若有需要恢復其他UI，請在此處實作
    }

    /**
     * @ch 恢復Extra Bet UI
     */
    private async RestoreExtraBetUI()
    {
        log( "RestoreExtraBetUI" );

        // 先把假轉輪 betMode 快取設好，避免 ForceSetExtraBet 內 ChangeMultiBet 連帶讀到舊值
        this.m_gameView.ForceSetFakeReelBetMode(FakeReelBetMode.ExtraBet);
        await this.m_gameView.RestoreExtraBetState();
    }

    /**
     * @ch 恢復所有UI
     */
    private async RestoreUI()
    {
        this.m_gameView.CheckBackground();
        if (this.m_gameView.IsFreeGame) {
            this.RestoreFreeGameUI();
        }
        else if (this.m_gameView.IsRespinGame) {
            this.RestoreRespinGameUI();
        }
        else {
            this.RestoreMainGameUI();
        }

        if (this.m_startRoundInfo) {
            // // 設定倍率
            // eventManager.Dispatch(MULTIPLIER_EVENT.SET_INDEX, this.m_startRoundInfo.PreMultiplierIndex, true);

            // 設定魔法罐等級
            eventManager.Dispatch(MAGIC_POT_EVENT.SET_LEVEL, this.m_startRoundInfo.PreScAccuStage);
        }

        if (this.m_gameView.UnshowSpinAck != null && commonGameManager.UnshowBaseBet < commonGameManager.UnshowRealBet) {
            await this.RestoreExtraBetUI();
        }
    }

    /**
     * @ch 恢復贏分
     */
    private RestoreWinValue()
    {
        log( "RestoreWinValue" );

        const totalWin = this.m_gameView.UnshowSpinAck?.TotalWin ?? 0;
        newBottombarManager.SetWinValueWithCheck( { maxWin: totalWin, value: this.m_previousAccumulatedWinValue } );
    }

    /**
     * @ch 取得免費遊戲總回合數
     * @return 免費遊戲總回合數
     */
    private GetFreeGameTotalRound(): number
    {
        if (this.m_unshowSpinAckQue.length === 0) {
            error("[UnshowPrepareState] UnshowSpinAckQue is empty");
            return 0;
        }

        // 如果起始盤面索引大於0，則返回上一輪的免費遊戲總回合數
        if (this.m_startRound >= 1 && this.m_startRound < this.m_unshowSpinAckQue.length) {
            return this.m_unshowSpinAckQue[this.m_startRound - 1].FreeTotalRound;
        }

        // 照理來說，這裡應該不會執行到
        return this.m_unshowSpinAckQue[0].FreeTotalRound ?? 0;
    }

    /**
     * @ch 處理RespinGame
     */
    /**@ch ⚠️ BC-8 待實測：unshow Respin 恢復暫改「從 plate 0 重播整局」由 ENTER_RESPIN 重建鎖定，
     * 此方法目前無呼叫者。待 Respin 上線後確認 unshow 是否需在 prepare 階段直接鎖列亮燈，
     * 屆時恢復呼叫或刪除。 */
    private HandleRespinGame()
    {
        log( "HandleRespinGame" );

        // 設定Respin鎖定列的旋轉鎖定
        Game_Define.RespinLockColumns.forEach( column => {
            this.m_gameView.SlotReels.SetColumnLock( column, true );
        } );

        // 設定轉輪亮燈一次
        eventManager.Dispatch(REEL_UI_EVENT.SHOW_LIGHT_LEFT_REEL);
        eventManager.Dispatch(REEL_UI_EVENT.SHOW_LIGHT_RIGHT_REEL);
    }

    /**
     * @ch 恢復背景音樂
     */
    private RestoreBgm()
    {
        this.m_gameView.PlayMainGameBgm();
        if (this.m_gameView.IsFreeGame) {
            this.m_gameView.PauseMainGameBgm();
            this.m_gameView.PlayFreeGameBgm();
        }
    }
}

