# -*- coding: utf-8 -*-
import json, io, sys
sys.stdout = io.TextIOWrapper(sys.stdout.buffer, encoding='utf-8')
d=json.load(open('.claude_temp/respin_and_freegame.json',encoding='utf-8'))
RQ=d['RoundQueue']; N=len(RQ)
pc=[len(r.get('PlateQueue',[])) for r in RQ]
locks=[[ (p.get('RespinLockedPos') or []) for p in r.get('PlateQueue',[])] for r in RQ]
wins=[[ p.get('Win',0) for p in r.get('PlateQueue',[])] for r in RQ]

def advance(round,sub,plateCount):
    return (round,sub+1) if sub < plateCount-1 else (round+1,0)
def plateCountOf(r): return pc[r] if 0<=r<N else 0
def IsGoingToRespin(sub,plateCount): return sub < plateCount-1
def IsGoingToFree(round,isFree): return round==0 and N>1 and not isFree

cur=(-1,0); isRespin=False; isFree=False
state='SPIN'; merged=set(); trace=[]; re_cnt=0; rend_cnt=0; guard=0
def emit(s): trace.append(s)

while state!='END':
    guard+=1
    if guard>500: emit('!! guard 上限'); break
    if state=='SPIN':
        cur=advance(cur[0],cur[1],plateCountOf(cur[0])); r,s=cur
        w=wins[r][s] if r<N and s<pc[r] else '?'
        emit('SPIN        cur=(%d,%d) plates=%s Win=%s'%(r,s,pc[r] if r<N else '?',w)); state='CHECK'
    elif state=='CHECK':
        r,s=cur
        if IsGoingToRespin(s, plateCountOf(r)):
            emit('  CHECK (1) IsGoingToRespin(sub%d<%d) -> ENTER_RESPIN'%(s,pc[r]-1)); state='ENTER_RESPIN'
        elif isRespin:
            emit('  CHECK (2) IsRespinGame(plate用盡) -> LEAVE_RESPIN'); state='LEAVE_RESPIN'
        elif IsGoingToFree(r,isFree):
            emit('  CHECK (3) IsGoingToFree -> ENTER_FREE'); state='ENTER_FREE'
        elif isFree and r+1==N:
            emit('  CHECK (4) IsFree&最後局(r+1=%d==%d) -> LEAVE_FREE'%(r+1,N)); state='LEAVE_FREE'
        else:
            emit('  CHECK (5) else -> ROUND_END'); state='ROUND_END'
    elif state=='ENTER_RESPIN':
        r,s=cur; first=not isRespin
        for p in locks[r][s]: merged.add(p)
        if first: isRespin=True
        re_cnt+=1
        emit('    ENTER_RESPIN (%s) merge plate[%d]鎖%d筆 累積=%d -> SPIN'%('首手·鎖col0/5·宣告' if first else '續轉手', s, len(locks[r][s]), len(merged))); state='SPIN'
    elif state=='LEAVE_RESPIN':
        r,s=cur; union=set()
        for pl in locks[r]:
            for p in pl: union.add(p)
        ok=(merged==union); isRespin=False
        emit('    LEAVE_RESPIN 解鎖 斷言%s(累積%d vs 聯集%d) 清集合'%('OK' if ok else 'X不一致', len(merged), len(union))); merged=set()
        if IsGoingToFree(r,isFree):
            emit('      LR(1) IsGoingToFree -> ENTER_FREE'); state='ENTER_FREE'
        elif isFree and r+1==N:
            emit('      LR(2) IsFree&最後局 -> LEAVE_FREE'); state='LEAVE_FREE'
        else:
            emit('      LR(3) else -> ROUND_END'); state='ROUND_END'
    elif state=='ENTER_FREE':
        isFree=True; emit('    ENTER_FREE (isFree=true) -> SPIN'); state='SPIN'
    elif state=='LEAVE_FREE':
        emit('    LEAVE_FREE -> END'); state='END'
    elif state=='ROUND_END':
        rend_cnt+=1; r,s=cur
        emit('    ROUND_END (ReqRoundEnd round=%d,isLast=%s) -> ForEndToNext: %s'%(r+1, str(r>=N-1), 'isFree->SPIN' if isFree else 'END'))
        state='SPIN' if (isFree or isRespin) else 'END'

print('\n'.join(trace))
print('\n=== 統計 ===')
print('ENTER_RESPIN 次數=%d  ROUND_END 次數=%d'%(re_cnt,rend_cnt))
print('plate counts per round =', pc)

